import React, { useEffect, useRef } from "react";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";

const Galeria = () => {
  const sectionRef = useRef(null);
  const rightWaveRef = useRef(null);
  const leftWaveRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          rightWaveRef.current?.classList.add("wave-visible");
          leftWaveRef.current?.classList.add("wave-visible");
        }
      },
      { threshold: 0.3 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={sectionRef} className="h-screen snap-start overflow-hidden relative bg-white flex flex-col justify-center">

      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
        <img
          ref={rightWaveRef}
          src={Wave}
          className="absolute w-[150vw] animate-spin-slow wave-right"
          style={{ top: '-70%', right: '-50vw', transformOrigin: 'center center' }}
        />
      </div>

      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
        <img
          ref={leftWaveRef}
          src={Wave}
          className="absolute w-[150vw] animate-spin-slow-reverse wave-left"
          style={{ top: '-30%', left: '-50vw', transformOrigin: 'center center' }}
        />
      </div>

      {/* CONTENIDO */}
      <div className="relative z-10 text-center mb-[3vh]">
        <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">
          ¿Te quedaste con ganas de ver más?
        </h1>
        <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]" />
      </div>

      <div className="relative z-10 w-[50%] mx-auto">
        <MasonryGrid />
      </div>

    </section>
  );
};

export default Galeria;
